-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 044 — SQL con Oracle · m09: Calidad y optimización
-- ═══════════════════════════════════════════════════════════════════
-- Cubre la Parte XII: SQL legible y mantenible (formato, alias,
-- CTEs sobre anidamiento, intención comentada), índices B-tree
-- (cuándo sí, cuándo no, y su costo en escrituras), el optimizador
-- de costos (CBO) y sus estadísticas (DBMS_STATS), EXPLAIN PLAN
-- para medir en vez de adivinar, y hints como último recurso.
-- Precisiones vinculantes: el FULL TABLE SCAN NO siempre es
-- problema (leer gran parte de la tabla lo vuelve lo más eficiente);
-- los hints NO garantizan mejora; una función sobre la columna
-- inutiliza su índice (recall de la conversión implícita del m05);
-- el orden de intervención: medir → estadísticas → reescribir →
-- índices → hints.
-- Práctica (hoja de diagnóstico): 4 casos de rendimiento.
-- Reglas de contenido: quizzes autocontenidos o con términos técnicos.
-- OJO: SQL con Oracle está PUBLICADO — esta migración sale en vivo.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 011 (estructura v2).
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'sql-oracle' and m.slug = 'm09-indices-tuning'
);

-- ── Lecciones del módulo ──────────────────────────────────────────────
insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
select m.id, v.slug, v.title, v.kind, v.xp, v.ord
from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m09-l01-sql-legible',      'SQL que otros puedan mantener',        'leccion',  20, 1),
       ('m09-l02-indices',          'Índices: el atajo con precio',         'leccion',  20, 2),
       ('m09-l03-cuando-no',        'Cuándo NO indexar (y el FTS honrado)', 'leccion',  20, 3),
       ('m09-l04-optimizador',      'El optimizador y sus estadísticas',    'leccion',  20, 4),
       ('m09-l05-explain',          'EXPLAIN PLAN: medir, no adivinar',     'leccion',  20, 5),
       ('m09-l06-hints',            'Hints: el último recurso',             'leccion',  20, 6),
       ('m09-l07-practica-tuning',  'Práctica: la hoja de diagnóstico',     'practica', 20, 7),
       ('m09-x01-examen',           'Examen: Calidad y optimización',       'examen',   40, 8)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'sql-oracle' and m.slug = 'm09-indices-tuning';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · SQL que otros puedan mantener
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La consulta se escribe una vez y se lee cien","body":"Antes de acelerar consultas, una verdad del oficio: la mayor parte del costo de una consulta NO es de CPU — es HUMANO: las horas que alguien (probablemente tu yo del futuro) gastará entendiéndola para corregirla o extenderla. La CALIDAD del SQL es eso: escribir para el lector. Las reglas de la casa, muchas ya tuyas: palabras clave en MAYÚSCULAS y columnas en minúsculas (el contraste guía al ojo), indentación consistente que alinee cláusulas, ALIAS significativos (c de citas, no t1 y t2), pedir las columnas que necesitas (no SELECT *: acopla el código a la tabla y arrastra datos de más), CTEs con nombres que narren en lugar de subconsultas-cebolla, y comentarios que expliquen la INTENCIÓN ('excluimos canceladas porque finanzas no las factura') — no la mecánica, que el SQL ya dice."}$j$),
  (2, 'ejemplo_sql', $j${"title":"La misma consulta, dos destinos","code":"-- ✗ funciona, pero nadie querrá tocarla:\n-- select * from citas t1, pacientes t2 where t1.paciente_id=t2.paciente_id and t1.estado='atendida'\n\n-- ✓ la versión que un equipo mantiene:\n-- Ingresos de citas atendidas (canceladas fuera: finanzas no las factura)\nSELECT p.nombre                AS paciente,\n       c.fecha,\n       c.costo\nFROM   citas c\nJOIN   pacientes p ON p.paciente_id = c.paciente_id\nWHERE  c.estado = 'atendida'\nORDER  BY c.fecha;","result":{"columns":["PACIENTE","FECHA","COSTO"],"rows":[["Laura Méndez","2026-07-02","950"],["Sofía Aguirre","2026-07-14","640"]],"note":"Mismo resultado, distinto futuro: la segunda versión declara qué pide (columnas explícitas), cómo conecta (ANSI JOIN con alias legibles) y POR QUÉ filtra (el comentario de intención). El motor las trata igual; el equipo, no."}}$j$),
  (3, 'texto', $j${"title":"Mantenible también es un contrato técnico","body":"La legibilidad no es estética: es correctitud diferida. El SELECT * que 'funciona' se rompe cuando la tabla gana una columna (¿recuerdas el INSERT posicional del m05? — mismo veneno); el alias t1 obliga a releer el FROM en cada línea; la subconsulta sin nombre esconde un negocio que nadie documentó. Y hay un beneficio extra que pocos mencionan: el SQL limpio es MÁS FÁCIL DE OPTIMIZAR — cuando la consulta lenta llegue (llegará), quien la diagnostique necesitará entender qué intenta hacer antes de decidir cómo acelerarla. Una consulta ilegible y lenta debe descifrarse ANTES de poder ajustarse: pagas dos veces. La calidad de este módulo y la velocidad del resto del módulo son la misma inversión."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué el oficio evita SELECT * en código de producción?","options":["Porque resulta más lento de escribir a mano","Porque Oracle lo prohíbe por completo","Acopla el código a la tabla y trae de más","Por una cuestión de pura estética"],"correctIndex":2,"feedback":{"correct":"Correcto. El * es una apuesta a que la tabla nunca cambie — el mismo veneno del INSERT posicional. Columnas explícitas = contrato explícito.","incorrect":"El * se rompe (o engorda) cuando la tabla evoluciona: pedir columnas explícitas es declarar qué necesitas y protegerte del cambio."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué debe explicar un buen comentario en una consulta SQL?","options":["Qué hace cada línea, una por una","La fecha exacta en que se escribió","El nombre completo de quien lo hizo","La intención de negocio del SQL"],"correctIndex":3,"feedback":{"correct":"Correcto. El SQL dice QUÉ hace; el comentario dice POR QUÉ. Comentar la mecánica es ruido; comentar la intención es documentación.","incorrect":"El comentario valioso explica el porqué del negocio — lo único que el código no puede decir por sí mismo."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"'Una consulta ilegible y lenta se paga dos veces.' ¿Por qué?","options":["Antes de acelerarla hay que descifrarla","Porque consume justo el doble de CPU","Porque Oracle cobra por cada consulta","No es cierto: solo se paga una vez"],"correctIndex":0,"feedback":{"correct":"Correcto. La legibilidad es prerequisito del tuning: el SQL limpio se optimiza directo; el sucio, primero se excava.","incorrect":"El diagnóstico exige comprensión: la consulta ilegible cobra la arqueología ANTES de permitir la optimización."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — SQL legible","points":["El costo dominante es HUMANO: se escribe una vez, se lee cien.","Mayúsculas para palabras clave, alias significativos, indentación consistente, CTEs que narran.","SELECT * y alias t1/t2: deuda que se cobra cuando la tabla o el equipo cambian.","Comentarios de INTENCIÓN (el porqué del negocio), no de mecánica.","La legibilidad es prerequisito del tuning: lo ilegible se paga dos veces."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm09-l01-sql-legible';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · Índices: el atajo con precio
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El índice del libro, para tablas","body":"Buscar un paciente por teléfono en una tabla de un millón de filas, sin ayuda, obliga a Oracle a revisarlas TODAS. El ÍNDICE es el mismo invento que el índice alfabético de un libro: una estructura APARTE, ORDENADA por la columna elegida, donde cada entrada apunta a la fila real. Con índice en telefono, la búsqueda salta directo — el B-tree (árbol balanceado, la variedad estándar) resuelve en un puñado de pasos lo que era un millón. Dos índices te regalan sin pedirlo: Oracle crea uno AUTOMÁTICO por cada PRIMARY KEY y cada UNIQUE — por eso buscar por PK siempre fue rápido. Para el resto, se declaran: CREATE INDEX cit_pac_idx ON citas (paciente_id) — y las FKs son las primeras candidatas, porque los JOINs las recorren todo el día."}$j$),
  (2, 'ejemplo_sql', $j${"title":"El atajo, declarado","code":"-- La búsqueda de todos los días:\n-- SELECT * FROM citas WHERE paciente_id = 12;\n\n-- Sin índice: revisar el millón de filas.\n-- Con índice: saltar directo.\nCREATE INDEX cit_pac_idx ON citas (paciente_id);\n\n-- Índices compuestos: para búsquedas de dos ejes\nCREATE INDEX cit_med_fecha_idx ON citas (medico_id, fecha);","result":{"columns":["RESULTADO"],"rows":[["Index CIT_PAC_IDX created."],["Index CIT_MED_FECHA_IDX created."]],"note":"El primero acelera los JOINs y búsquedas por paciente (una FK: candidata natural). El compuesto sirve a la agenda por médico y fecha — y el ORDEN de sus columnas importa: sirve para buscar por medico_id solo, pero no por fecha sola (como el directorio telefónico: apellido-nombre no ayuda a buscar por nombre)."}}$j$),
  (3, 'texto', $j${"title":"El precio del atajo","body":"Si los índices aceleran, ¿por qué no indexar TODO? Porque el atajo cobra renta: el índice es una estructura que Oracle debe MANTENER — cada INSERT agrega una entrada, cada DELETE la quita, cada UPDATE de la columna indexada la reubica. Diez índices en una tabla = cada INSERT paga once escrituras (la fila + diez entradas). En tablas de captura intensa (la mesa de citas en hora pico), el exceso de índices vuelve lenta PRECISAMENTE la operación que más importa. Además ocupan espacio real. La regla del oficio: los índices se SIEMBRAN CON CRITERIO — FKs que se joinean, columnas de búsqueda frecuente y ALTA SELECTIVIDAD (que filtran mucho: un teléfono casi único, no un 'sexo' de dos valores) — y se REVISAN: el índice que ninguna consulta usa es renta pura sin atajo."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué es un índice B-tree y qué problema resuelve?","options":["Una copia completa de la tabla original","Estructura aparte ordenada con punteros","Un tipo especial de constraint nuevo","Un respaldo hecho automáticamente"],"correctIndex":1,"feedback":{"correct":"Correcto. El índice del libro, para tablas: ordenado, aparte, y apuntando a las filas.","incorrect":"El índice no duplica la tabla: es la estructura ordenada auxiliar que permite saltar directo a las filas buscadas."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué columnas reciben índice AUTOMÁTICO de Oracle, sin que lo pidas?","options":["Todas las columnas de tipo NUMBER","Todas las columnas marcadas NOT NULL","Las de PRIMARY KEY y las UNIQUE","Todas las claves foráneas (FK)"],"correctIndex":2,"feedback":{"correct":"Correcto. PK y UNIQUE traen su índice de fábrica. Las FKs — irónicamente las más joineadas — NO: se indexan a mano.","incorrect":"Oracle indexa solo PK y UNIQUE automáticamente. Las FKs son la primera candidata MANUAL, porque los JOINs las recorren a diario."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál es el PRECIO de cada índice que agregas a una tabla?","options":["Ninguno: los índices son del todo gratis","Solo el espacio que ocupan en disco","Requiere una licencia adicional aparte","Cada escritura debe mantenerlo también"],"correctIndex":3,"feedback":{"correct":"Correcto. El atajo de lectura cobra renta de escritura: diez índices = cada INSERT paga once. Se siembra con criterio.","incorrect":"El índice se MANTIENE en cada escritura: acelera el SELECT cobrándole al INSERT/UPDATE/DELETE. Por eso no se indexa todo."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Índices","points":["Índice = estructura aparte, ORDENADA, con punteros: el índice del libro para tablas.","PK y UNIQUE traen índice automático; el resto se declara (CREATE INDEX … ON tabla (columna)).","Candidatas: FKs (los JOINs las recorren), búsquedas frecuentes, alta selectividad.","En los compuestos el ORDEN importa: (medico_id, fecha) no sirve para buscar por fecha sola.","El precio: cada escritura mantiene también el índice — sembrar con criterio y revisar el uso."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm09-l02-indices';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · Cuándo NO indexar (y el FTS honrado)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El FULL TABLE SCAN no es una mala palabra","body":"Precisión vinculante que separa al profesional del repetidor de mitos: ver FULL TABLE SCAN (FTS) en un plan NO significa automáticamente que algo esté mal. El FTS — leer la tabla completa de corrido — es la estrategia MÁS EFICIENTE cuando la consulta necesita GRAN PARTE de la tabla: el reporte mensual que toca el 80% de las citas iría MÁS LENTO saltando por el índice (millones de brincos individuales) que leyendo de corrido (lectura secuencial, multibloque, imparable). El índice brilla para encontrar AGUJAS; el FTS, para cosechar CAMPOS. También es honrado en tablas pequeñas: leer completo un catálogo de 50 medicamentos cuesta menos que consultar el índice primero. El diagnóstico correcto nunca es 'hay un FTS'; es '¿este FTS corresponde a lo que la consulta pide?'."}$j$),
  (2, 'texto', $j${"title":"Los índices que no pagan (y el asesino silencioso)","body":"Tres escenarios donde el índice NO paga su renta: tablas PEQUEÑAS (el FTS ya es barato), columnas de BAJA SELECTIVIDAD (indexar una columna con dos valores — activo S/N — apenas filtra: media tabla sigue siendo media tabla) y columnas MUY ACTUALIZADAS (cada cambio reubica la entrada: renta máxima). Y el asesino silencioso que ya conociste en el m05: una FUNCIÓN SOBRE LA COLUMNA inutiliza su índice — WHERE UPPER(nombre) = 'ANA' no puede usar el índice de nombre, porque el índice guarda 'Ana', no 'ANA': Oracle debe evaluar la función fila por fila… es decir, FTS aunque el índice exista. Lo mismo hace la conversión implícita (comparar la columna texto con un número). Salidas: reescribir para dejar la columna LIMPIA en el WHERE, o — si la búsqueda insensible es la norma — un ÍNDICE DE FUNCIÓN: CREATE INDEX … ON pacientes (UPPER(nombre)), que indexa el resultado de la función."}$j$),
  (3, 'ejemplo_sql', $j${"title":"El índice ignorado y sus dos rescates","code":"-- El índice existe… y esta consulta NO puede usarlo:\nSELECT * FROM pacientes WHERE UPPER(nombre) = 'ANA TORRES';\n-- (la función sobre la columna obliga a evaluar fila por fila)\n\n-- Rescate 1 · dejar la columna limpia (si la captura es consistente):\nSELECT * FROM pacientes WHERE nombre = 'Ana Torres';\n\n-- Rescate 2 · si la búsqueda insensible es la norma,\n--             indexar EL RESULTADO de la función:\nCREATE INDEX pac_nombre_up_idx ON pacientes (UPPER(nombre));","result":{"columns":["RESULTADO"],"rows":[["Index PAC_NOMBRE_UP_IDX created."]],"note":"Con el índice de función, WHERE UPPER(nombre) = 'ANA TORRES' vuelve a saltar directo: el índice guarda los valores YA transformados. La conversión implícita del m05 causa el mismo síntoma — y el mismo diagnóstico: la columna del WHERE debe quedar tal cual el índice la conoce."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de certificación: aparece un FULL TABLE SCAN en el plan de tu reporte mensual (que lee el 80% de la tabla). ¿Es un problema?","options":["No: leer mucho de corrido es eficiente","Sí: absolutamente todo FTS es un problema","Sí, salvo en las tablas que tienen PK","Solo es un problema en Oracle 11g"],"correctIndex":0,"feedback":{"correct":"Correcto. Índice para agujas, FTS para cosechas: el 80% de la tabla se cosecha, no se busca aguja por aguja.","incorrect":"El FTS es la estrategia honrada para consultas que tocan mucho de la tabla (y para tablas pequeñas). El mito de 'FTS = malo' delata al repetidor."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué NO conviene indexar la columna activo, que solo vale 'S' o 'N' en una tabla de un millón de filas?","options":["Porque los CHAR no se pueden indexar","Por baja selectividad: filtra muy poco","Porque las columnas con CHECK no aceptan","Sí conviene indexarla, en todos los casos"],"correctIndex":1,"feedback":{"correct":"Correcto. El índice paga cuando FILTRA mucho: dos valores posibles filtran poco, y la renta de mantenimiento se paga igual.","incorrect":"Selectividad = cuánto filtra: una columna de dos valores deja media tabla viva — el índice no ahorra y sí cobra renta."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"WHERE UPPER(nombre) = 'ANA' va lento aunque nombre tiene índice. ¿Causa y salidas?","options":["El índice está corrupto y hay que recrearlo","Falta memoria física en el servidor","La función sobre la columna ciega el índice","Los índices no sirven con texto"],"correctIndex":2,"feedback":{"correct":"Correcto. El asesino silencioso: la columna transformada ya no coincide con lo indexado. Columna limpia o índice de función.","incorrect":"La función (o la conversión implícita) sobre la columna del WHERE obliga a evaluar fila por fila: el índice existe pero no aplica."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Cuándo no indexar","points":["FTS NO es mala palabra: para gran parte de la tabla (o tablas pequeñas) es LO más eficiente.","El diagnóstico correcto: ¿el FTS corresponde a lo que la consulta pide?","No pagan: tablas pequeñas, baja selectividad (activo S/N), columnas muy actualizadas.","Función o conversión implícita SOBRE la columna = índice inutilizado (evaluación fila por fila).","Salidas: columna limpia en el WHERE, o índice de función (UPPER(nombre))."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm09-l03-cuando-no';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · El optimizador y sus estadísticas
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El estratega que decide por ti","body":"Tú escribes QUÉ quieres; alguien decide CÓMO conseguirlo. Ese alguien es el OPTIMIZADOR DE COSTOS (CBO, Cost-Based Optimizer): por cada consulta genera PLANES candidatos — ¿índice o FTS? ¿en qué orden joinear las tablas? ¿con qué método? — le asigna a cada uno un COSTO estimado (lecturas, CPU, memoria) y ejecuta el más barato. Es la razón por la que SQL es declarativo: tú declaras el resultado, el estratega elige la ruta. Y como todo estratega, decide con la INFORMACIÓN que tiene: las ESTADÍSTICAS — cuántas filas tiene cada tabla, cómo se distribuyen los valores de cada columna, qué tan selectivo es cada índice. Buenas estadísticas, buenas decisiones; estadísticas viejas… la siguiente sección."}$j$),
  (2, 'texto', $j${"title":"Estadísticas viejas, decisiones absurdas","body":"El caso clásico que verás en la vida real: la tabla de citas tenía mil filas cuando se recolectaron estadísticas; hoy tiene diez millones. El optimizador — que sigue creyendo en las mil — elige planes de tabla chica (FTS alegre, joins de memoria) para una tabla que ya es un monstruo: la consulta que volaba ahora se arrastra, SIN que nadie tocara el SQL. Por eso la primera pregunta del diagnóstico profesional no es '¿qué índice falta?' sino '¿las estadísticas están al día?'. Se recolectan con el paquete DBMS_STATS (Oracle moderno lo hace solo en ventanas de mantenimiento, pero tras una CARGA MASIVA se recolecta a mano: la carga acaba de invalidar la foto). La moraleja para entrevista: el optimizador no es tonto ni caprichoso — decide bien con datos buenos, y decide EXACTAMENTE IGUAL de bien con datos malos: mal."}$j$),
  (3, 'ejemplo_sql', $j${"title":"Refrescar la foto tras la carga","code":"-- Tras cargar el histórico de 10 millones de citas:\nBEGIN\n  DBMS_STATS.GATHER_TABLE_STATS(\n    ownname => USER,\n    tabname => 'CITAS'\n  );\nEND;\n/","result":{"columns":["RESULTADO"],"rows":[["PL/SQL procedure successfully completed."]],"note":"La foto se actualizó: filas, distribución de valores y selectividad de índices vuelven a describir la realidad. El optimizador decide con lo que sabe — y ahora sabe la verdad. (El bloque BEGIN/END es PL/SQL: el próximo módulo te lo presenta en forma.)"}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué hace el optimizador de costos (CBO) con cada consulta?","options":["La ejecuta línea por línea como se escribió","La traduce a otro lenguaje interno","La guarda en caché para siempre","Genera planes, estima costos y elige"],"correctIndex":3,"feedback":{"correct":"Correcto. SQL es declarativo porque hay un estratega eligiendo la ruta: el CBO y sus costos estimados.","incorrect":"El CBO compara rutas posibles por costo estimado y elige: por eso el mismo SQL puede ejecutarse distinto según el contexto."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Una consulta que volaba se arrastra desde la carga masiva de anoche — y nadie tocó el SQL. ¿El primer sospechoso profesional?","options":["Estadísticas viejas: usar DBMS_STATS","Un virus atacó la base de datos","El SQL se corrompió por sí solo","Hace falta reiniciar entero el servidor"],"correctIndex":0,"feedback":{"correct":"Correcto. La carga invalidó la foto: el estratega decide con datos falsos. DBMS_STATS antes de tocar ningún índice.","incorrect":"Mismo SQL + datos nuevos + plan viejo = estadísticas vencidas. La primera pregunta del diagnóstico: ¿la foto está al día?"}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué contienen las ESTADÍSTICAS de las que depende el optimizador?","options":["Los errores históricos de la base","Filas, distribución y selectividad","Las contraseñas de todos, cifradas","El historial de consultas por usuario"],"correctIndex":1,"feedback":{"correct":"Correcto. La foto demográfica de tus datos: con ella el CBO estima cuánto costará cada ruta posible.","incorrect":"Estadísticas = la descripción de tus datos (volumen, distribución, selectividad): el insumo de toda estimación de costo."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — El optimizador","points":["El CBO genera planes candidatos, estima costos y ejecuta el más barato: tú declaras, él decide.","Decide con ESTADÍSTICAS: filas, distribución de valores, selectividad de índices.","Estadísticas viejas = decisiones absurdas con el mismo SQL (la tabla creció, la foto no).","Tras una carga masiva: DBMS_STATS.GATHER_TABLE_STATS a mano — la carga invalidó la foto.","Primera pregunta del diagnóstico: ¿las estadísticas están al día? (antes que ningún índice)."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm09-l04-optimizador';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · EXPLAIN PLAN: medir, no adivinar
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Pedirle al estratega que enseñe su plan","body":"La consulta está lenta. El aficionado ADIVINA ('ha de faltar un índice') y dispara remedios al azar; el profesional MIDE: le pide al optimizador que muestre su plan antes de tocar nada. EXPLAIN PLAN FOR tu-consulta le pide al CBO que guarde el plan que USARÍA (sin ejecutar la consulta), y SELECT * FROM TABLE(DBMS_XPLAN.DISPLAY) lo muestra legible: un árbol de operaciones con sus costos y filas estimadas. Las operaciones que aprenderás a reconocer primero: TABLE ACCESS FULL (el FTS — y ya sabes juzgarlo con justicia), INDEX UNIQUE SCAN (búsqueda exacta por índice único: la más barata), INDEX RANGE SCAN (rango por índice: el paciente_id = 12 con su índice), y los métodos de join — NESTED LOOPS (bueno para pocas filas guiadas por índice) y HASH JOIN (bueno para volúmenes grandes). El plan se lee de adentro hacia afuera: las operaciones más anidadas corren primero."}$j$),
  (2, 'ejemplo_sql', $j${"title":"El plan, sobre la mesa","code":"EXPLAIN PLAN FOR\nSELECT p.nombre, c.fecha, c.costo\nFROM   citas c\nJOIN   pacientes p ON p.paciente_id = c.paciente_id\nWHERE  c.paciente_id = 12;\n\nSELECT * FROM TABLE(DBMS_XPLAN.DISPLAY);","result":{"columns":["PLAN_TABLE_OUTPUT"],"rows":[["| 0 | SELECT STATEMENT              |          |"],["| 1 |  NESTED LOOPS                 |          |"],["| 2 |   TABLE ACCESS BY INDEX ROWID | PACIENTES|"],["| 3 |    INDEX UNIQUE SCAN          | PAC_PK   |"],["| 4 |   TABLE ACCESS BY INDEX ROWID | CITAS    |"],["| 5 |    INDEX RANGE SCAN           | CIT_PAC_IDX |"]],"note":"El estratega enseñó su ruta: encuentra al paciente 12 por su PK (INDEX UNIQUE SCAN), y sus citas por el índice de la FK (INDEX RANGE SCAN), uniendo con NESTED LOOPS — la ruta de agujas, perfecta para pocas filas. Si aquí apareciera TABLE ACCESS FULL sobre citas, la pregunta sería: ¿corresponde a lo que pido? (una fila de paciente: no — falta el índice o está inutilizado)."}}$j$),
  (3, 'texto', $j${"title":"El método: medir → explicar → corregir → volver a medir","body":"Con el plan en la mano, el diagnóstico es un método y no una lotería: (1) ¿el plan corresponde a la consulta? — un FTS sobre millones para devolver tres filas huele a índice ausente o inutilizado (¿función sobre la columna? ¿conversión implícita?); (2) ¿las ESTIMACIONES del plan suenan a tus datos? — si el plan espera 10 filas donde hay 10 millones, las estadísticas mienten: DBMS_STATS primero; (3) corrige UNA cosa (estadísticas, reescritura, índice) y VUELVE A MEDIR — el plan nuevo confirma o desmiente. Nunca dos cambios a ciegas: no sabrías cuál funcionó. Este ciclo — medir, explicar, corregir, re-medir — es idéntico al método científico, y es la diferencia entre optimizar y suponer. El plan es tu instrumento de medición: sin él, todo tuning es superstición."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué hace EXPLAIN PLAN FOR + DBMS_XPLAN.DISPLAY?","options":["Ejecuta la consulta mucho más rápido","Repara todos los índices que estén dañados","Muestra el plan sin ejecutar la consulta","Borra por completo la caché del plan"],"correctIndex":2,"feedback":{"correct":"Correcto. El estratega enseña su ruta antes de correrla: con eso se diagnostica en vez de adivinar.","incorrect":"EXPLAIN PLAN no acelera nada por sí mismo: revela CÓMO se ejecutaría la consulta — el punto de partida de todo diagnóstico serio."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"En un plan, ¿qué diferencia a INDEX UNIQUE SCAN, INDEX RANGE SCAN y TABLE ACCESS FULL?","options":["Son en realidad exactamente sinónimos","El primero es de PK; los otros de vistas","Solo cambia el nombre según la versión","Exacto por índice · rango · tabla entera"],"correctIndex":3,"feedback":{"correct":"Correcto. Las tres formas de acceso que leerás a diario — y la tercera se juzga por contexto, no por reflejo.","incorrect":"UNIQUE SCAN = una fila exacta; RANGE SCAN = un rango del índice; ACCESS FULL = la tabla entera (¿corresponde a lo pedido?)."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"El plan estima 10 filas para una tabla que tiene 10 millones. ¿Qué revela y cuál es el siguiente paso?","options":["Las estadísticas mienten: usar DBMS_STATS","Que la tabla está prácticamente vacía","Que hay que agregar un hint de inmediato","Que el plan es del todo correcto"],"correctIndex":0,"feedback":{"correct":"Correcto. Estimación absurda = foto vencida. Se corrige la información antes que la estrategia — y se re-mide.","incorrect":"Cuando las estimaciones no suenan a tus datos, el problema es la foto (estadísticas), no la ruta: DBMS_STATS y re-medir."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — EXPLAIN PLAN","points":["Medir antes de tocar: EXPLAIN PLAN FOR + DBMS_XPLAN.DISPLAY muestran la ruta sin ejecutarla.","Vocabulario: TABLE ACCESS FULL · INDEX UNIQUE/RANGE SCAN · NESTED LOOPS (agujas) · HASH JOIN (volúmenes).","El plan se lee de adentro hacia afuera.","Estimaciones absurdas = estadísticas vencidas: corrige la información antes que la estrategia.","El método: medir → explicar → corregir UNA cosa → volver a medir. Sin plan, el tuning es superstición."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm09-l05-explain';

-- ═════════════════════════════════════════════════════════════════════
-- L06 · Hints: el último recurso
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Susurrarle al estratega","body":"Los HINTS son instrucciones incrustadas en un comentario especial — SELECT /*+ INDEX(c cit_pac_idx) */ … — con las que le sugieres al optimizador una decisión concreta: usa este índice, prefiere este método de join, lee esta tabla completa. Existen porque a veces sabes algo que las estadísticas no capturan. Pero la precisión vinculante va primero: un hint NO GARANTIZA ninguna mejora — es una sugerencia que el optimizador puede incluso ignorar si es inaplicable, y si la sugerencia es mala, la consulta empeora con tu firma en el crimen. Peor: el hint se ESCRIBE UNA VEZ Y SE QUEDA — los datos crecen, los índices cambian, Oracle se actualiza… y tu hint de 2026 sigue forzando la estrategia de 2026 en el mundo de 2029, impidiéndole al optimizador usar lo que aprendió."}$j$),
  (2, 'ejemplo_sql', $j${"title":"El susurro (documentado, como debe ser)","code":"-- Último recurso, tras medir: las estadísticas están al día,\n-- la consulta ya se reescribió, y el plan aún elige mal para\n-- este caso específico. Se fuerza el índice — Y SE DOCUMENTA:\n\nSELECT /*+ INDEX(c cit_pac_idx) */\n       c.cita_id, c.fecha, c.costo\nFROM   citas c\nWHERE  c.paciente_id = 12;\n\n-- Revisar en la próxima actualización de versión: el optimizador\n-- podría ya elegir bien sin ayuda.","result":{"columns":["CITA_ID","FECHA","COSTO"],"rows":[["517","2026-07-02","950"],["523","2026-07-10","350"]],"note":"El hint vive dentro del comentario /*+ … */ (la sintaxis exacta importa: sin el +, es un comentario común y Oracle lo ignora por completo). La nota de revisión no es cortesía: es el plan de retiro del hint."}}$j$),
  (3, 'texto', $j${"title":"La escalera de intervención (memorízala en orden)","body":"Cuando una consulta está lenta, el oficio sube una escalera de menor a mayor invasión — y los hints viven en el último peldaño: (1) MEDIR: EXPLAIN PLAN — sin diagnóstico no hay tratamiento; (2) ESTADÍSTICAS: ¿la foto está al día? DBMS_STATS es la corrección más barata y frecuente; (3) REESCRIBIR: ¿una función inutiliza el índice? ¿un NOT IN que debía ser NOT EXISTS? ¿un SELECT * arrastrando columnas? — el SQL limpio del inicio del módulo paga aquí; (4) ÍNDICES: sembrar (o podar) con criterio; (5) HINTS: solo cuando todo lo anterior se agotó, para un caso específico, documentado y con plan de retiro. Saltarse la escalera — el hint como primer reflejo — es tratar el síntoma anestesiando al médico: el optimizador, con buena información, casi siempre decide mejor que nosotros."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de certificación: ¿qué garantiza un hint como /*+ INDEX(...) */?","options":["Que la consulta será siempre más rápida","Nada: es una sugerencia ignorable","Que el índice se creará si no existe","Que el plan queda congelado por siempre"],"correctIndex":1,"feedback":{"correct":"Correcto. El hint no garantiza mejora — y se queda en el código forzando la estrategia de ayer en los datos de mañana.","incorrect":"Los hints no garantizan nada: sugieren. La mejora depende de que tu intuición supere a las estadísticas — hoy Y en tres años."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"La escalera de intervención ante una consulta lenta, en orden:","options":["Hints, luego índices, luego medir","Medir → estadísticas → SQL → índices → hint","Reiniciar, esperar y después hints","Poner índices en todas las columnas primero"],"correctIndex":1,"feedback":{"correct":"Correcto. De menor a mayor invasión — y el hint como primer reflejo es anestesiar al médico.","incorrect":"Primero el diagnóstico (plan), luego la información (estadísticas), luego el SQL, luego estructuras (índices) y AL FINAL los hints."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué un hint que hoy funciona puede ser un problema en tres años?","options":["Los hints caducan por la licencia","La sintaxis cambia en cada versión","No puede: si funcionó, funciona siempre","Congela la estrategia de hoy en el futuro"],"correctIndex":3,"feedback":{"correct":"Correcto. El hint congela una decisión en un mundo que se mueve: por eso se documenta con plan de retiro.","incorrect":"El hint no envejece con gracia: sigue forzando la ruta de 2026 en el mundo de 2029. Documentar y revisar es parte del trato."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Hints","points":["Hint = sugerencia incrustada (/*+ … */) al optimizador: usa este índice, este join, esta ruta.","PRECISIÓN: no garantizan mejora — pueden ignorarse, y una mala sugerencia empeora la consulta.","Envejecen mal: fuerzan la estrategia de hoy en los datos de mañana.","La escalera: medir → estadísticas → reescribir → índices → hints (último peldaño).","Si se usa: caso específico, documentado, con plan de retiro."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm09-l06-hints';

-- ═════════════════════════════════════════════════════════════════════
-- L07 · Práctica: la hoja de diagnóstico (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"El equipo te dejó la hoja de incidentes de rendimiento de la semana. El caso 1 viene diagnosticado de ejemplo; completa los demás con la respuesta exacta (en minúsculas, tal como aparece en las opciones de cada caso).","instructions":["Caso 2 — El reporte mensual lee el 85% de la tabla y su plan muestra TABLE ACCESS FULL. ¿Es un problema? (si/no)","Caso 3 — WHERE TO_CHAR(fecha, 'YYYY') = '2026' va lento aunque fecha tiene índice. ¿La causa? (indice_ausente / funcion_sobre_columna / tabla_pequena)","Caso 4 — Desde la carga masiva de anoche, una consulta que volaba se arrastra — nadie tocó el SQL. ¿El primer remedio? (hint / estadisticas / mas_indices)","Caso 5 — Un compañero propone arrancar el diagnóstico agregando /*+ INDEX */ 'para asegurar'. ¿Un hint garantiza mejora? (si/no)"],"initialCode":"-- HOJA DE DIAGNÓSTICO — incidentes de la semana\n\n-- Caso 1 (ejemplo): buscar UNA cita por cita_id usa\n--   INDEX UNIQUE SCAN → comportamiento correcto\ncaso1_correcto=si\n\n-- Caso 2: FTS en reporte que lee el 85% de la tabla\ncaso2_fts_problema=?\n\n-- Caso 3: TO_CHAR(fecha,…) en el WHERE, índice ignorado\ncaso3_causa=?\n\n-- Caso 4: lentitud súbita tras carga masiva\ncaso4_remedio=?\n\n-- Caso 5: ¿el hint garantiza mejora?\ncaso5_hint_garantiza=?","validators":["caso2_fts_problema\\s*=\\s*no\\b","caso3_causa\\s*=\\s*funcion_sobre_columna\\b","caso4_remedio\\s*=\\s*estadisticas\\b","caso5_hint_garantiza\\s*=\\s*no\\b"],"mockOutput":{"columns":["CASO","DIAGNÓSTICO","POR QUÉ"],"rows":[["1 · búsqueda por PK","correcto","INDEX UNIQUE SCAN es la ruta más barata para una fila exacta"],["2 · FTS en reporte del 85%","no es problema","leer casi toda la tabla de corrido es MÁS eficiente que millones de saltos por índice"],["3 · TO_CHAR en el WHERE","funcion_sobre_columna","la columna transformada ya no coincide con lo indexado: se evalúa fila por fila"],["4 · lentitud tras carga","estadisticas","la carga invalidó la foto: DBMS_STATS antes de tocar índices o SQL"],["5 · hint 'para asegurar'","no","el hint es una sugerencia — no garantiza nada y envejece mal: es el ÚLTIMO peldaño"]],"note":"La hoja completa: cuatro incidentes, cuatro diagnósticos con método — y ni un remedio disparado al azar."},"hints":["Caso 2: índice para agujas, FTS para cosechas — ¿el 85% de la tabla es aguja o cosecha?","Caso 3: el índice guarda la fecha original; TO_CHAR la transforma antes de comparar. Caso 4: ¿qué invalidó la carga masiva — el SQL o la foto de los datos?","Caso 5: la escalera de intervención pone los hints en el último peldaño precisamente porque no garantizan nada."],"successMessage":"Hoja de diagnóstico entregada: juzgaste el FTS por contexto, cazaste al asesino silencioso del índice, refrescaste la foto antes de tocar estructuras y pusiste el hint en su lugar (el último). Ese es el método: medir, explicar, corregir — jamás adivinar.","failMessage":"Revisa: caso2=no (el 85% se cosecha de corrido) · caso3=funcion_sobre_columna (TO_CHAR transforma lo indexado) · caso4=estadisticas (la carga invalidó la foto) · caso5=no (el hint sugiere, no garantiza)."}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm09-l07-practica-tuning';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen de región (jefe del módulo)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La undécima región","body":"Byte ya escribe SQL que funciona; esta región exige SQL que funcione BIEN — legible para humanos y veloz para máquinas, con diagnósticos medidos y ni una superstición. Once preguntas custodian el paso. Las que falles volverán al final hasta que las domines. Adelante."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál es el argumento profesional contra SELECT * y los alias t1/t2 en código de producción?","options":["El costo es humano: acoplan y confunden","Siempre consumen muchísima más CPU al correr","Están deprecados dentro de Oracle","Ninguno: son del todo equivalentes"],"correctIndex":0,"feedback":{"correct":"Correcto. Se escribe una vez y se lee cien: la calidad es para el lector — que suele ser tu yo del futuro.","incorrect":"La factura es de mantenimiento: contratos implícitos (*) y nombres sin significado (t1) se cobran en cada lectura y cada cambio."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué es un índice y cuál es su renta?","options":["Una copia completa de la tabla, del todo gratis","Estructura con punteros; se paga al escribir","Es un simple constraint de unicidad","Es una vista materializada guardada"],"correctIndex":1,"feedback":{"correct":"Correcto. Atajo de lectura, renta de escritura: por eso se siembra con criterio y no en todas las columnas.","incorrect":"El índice acelera el SELECT cobrándole a las escrituras su mantenimiento: nunca es gratis."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Qué índices existen en una tabla recién creada con PRIMARY KEY y una constraint UNIQUE, sin ningún CREATE INDEX?","options":["Ninguno en absoluto, sin CREATE INDEX","Uno por cada una de las columnas","Dos: uno por la PK y uno por la UNIQUE","Solo el de la PRIMARY KEY, uno"],"correctIndex":2,"feedback":{"correct":"Correcto. La unicidad se vigila con esa estructura: PK y UNIQUE traen su índice de fábrica. Las FKs no — y son las primeras candidatas manuales.","incorrect":"PK y UNIQUE crean índice automático (así vigilan la unicidad). La FK joineada a diario es tu primera candidata a CREATE INDEX."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión vinculante: ¿cuándo es el FULL TABLE SCAN la estrategia CORRECTA?","options":["Nunca: siempre es un claro problema","Solamente en las bases de prueba","Cuando no hay ninguna estadística","Cuando se lee gran parte de la tabla"],"correctIndex":3,"feedback":{"correct":"Correcto. Índice para agujas, FTS para cosechas: el mito de 'FTS = malo' delata al repetidor.","incorrect":"El FTS es honrado para cosechas (gran parte de la tabla) y tablas chicas: se juzga por contexto, jamás por reflejo."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Una columna con solo dos valores posibles ('S'/'N') en una tabla enorme, ¿por qué es MALA candidata a índice?","options":["Baja selectividad: filtra media tabla","Porque los índices no aceptan datos CHAR","Porque tiene una constraint CHECK","Porque ya trae índice automático"],"correctIndex":0,"feedback":{"correct":"Correcto. El índice paga cuando filtra mucho: dos valores casi no filtran, y la renta se paga igual.","incorrect":"Selectividad baja = el índice apunta a media tabla: más caro saltar que leer de corrido, y el mantenimiento se cobra en cada escritura."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"WHERE UPPER(apellido) = 'TORRES' ignora el índice de apellido. Las DOS salidas profesionales:","options":["Reiniciar el servidor y luego rezar","Columna limpia o índice de función","Quitar el índice y crear otro igual","Convertir la columna entera a NUMBER"],"correctIndex":1,"feedback":{"correct":"Correcto. El índice guarda 'Torres', no 'TORRES': o comparas sin transformar, o indexas lo transformado.","incorrect":"Función sobre la columna = índice ciego. Columna limpia en el WHERE, o índice de función que guarde el resultado transformado."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Con qué INFORMACIÓN decide el optimizador de costos, y qué pasa cuando esa información envejece?","options":["Con el historial de usuarios; nada pasa","Con la hora del día; el CBO se pausa","Con estadísticas: viejas, decide mal","Con los hints, y entonces mejora sola"],"correctIndex":2,"feedback":{"correct":"Correcto. El estratega decide igual de bien con datos malos: mal. DBMS_STATS es la corrección más barata y frecuente.","incorrect":"El CBO estima costos con las estadísticas: la foto vencida produce decisiones absurdas con el mismo SQL de siempre."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál es el papel de EXPLAIN PLAN en el método de optimización?","options":["Acelera la consulta al correrla dos veces","Se encarga de reparar las estadísticas","Sustituye por completo a los índices","Es el instrumento de medición del tuning"],"correctIndex":3,"feedback":{"correct":"Correcto. Medir → explicar → corregir UNA cosa → re-medir: el plan es el inicio y el final de cada ciclo.","incorrect":"EXPLAIN PLAN no acelera: revela. El diagnóstico medido es lo que separa optimizar de adivinar."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión vinculante sobre los HINTS:","options":["No garantizan nada: sugieren y envejecen","Garantizan mejora si la sintaxis va bien","Se aplican solos a consultas lentas","Sustituyen del todo a las estadísticas"],"correctIndex":0,"feedback":{"correct":"Correcto. Sugerencia, no contrato — y con fecha de caducidad no escrita: por eso viven en el último peldaño.","incorrect":"El hint sugiere y a veces ni se aplica; cuando se aplica mal (o envejece), empeora las cosas con tu firma."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"La escalera de intervención completa ante una consulta lenta:","options":["Un hint primero, por si acaso funciona","Medir, estadísticas, SQL, índices, hints","Índices en todo, reiniciar y esperar","Aumentar la memoria total del servidor"],"correctIndex":1,"feedback":{"correct":"Correcto. De menor a mayor invasión, corrigiendo UNA cosa por ciclo y re-midiendo.","incorrect":"El orden importa: diagnóstico (plan), información (estadísticas), código (reescritura), estructura (índices) y solo al final la imposición (hints)."}}$j$),
